/* Riftbound Offline Card DB — viewer logic.
 *
 * Data: ./data/cards.json (text/stats, generated by scripts/fetch-cards.mjs).
 * Images are NOT downloaded by default — thumbnails load from the live CDN when
 * online, and are cached by the service worker as you view them. The "Download
 * images for offline" button pre-fetches every card image into the SW cache.
 * Freshness: we compare our local buildId against the live gallery's buildId. */

const IMG_CACHE = "rb-images-v1";
const els = {
  grid: document.getElementById("grid"),
  empty: document.getElementById("empty"),
  count: document.getElementById("count"),
  q: document.getElementById("q"),
  fSet: document.getElementById("fSet"),
  fType: document.getElementById("fType"),
  fDomain: document.getElementById("fDomain"),
  fRarity: document.getElementById("fRarity"),
  net: document.getElementById("netState"),
  gen: document.getElementById("genState"),
  fresh: document.getElementById("freshState"),
  imgBtn: document.getElementById("imgBtn"),
  imgProg: document.getElementById("imgProg"),
  imgState: document.getElementById("imgState"),
  modal: document.getElementById("modal"),
};

let DB = { cards: [] };
let filtered = [];

function fillSelect(sel, values) {
  for (const v of values) {
    const o = document.createElement("option");
    o.value = v; o.textContent = v; sel.appendChild(o);
  }
}

function cardMatches(c, terms, f) {
  if (f.set && c.set !== f.set) return false;
  if (f.type && c.type !== f.type) return false;
  if (f.domain && !c.domains.includes(f.domain)) return false;
  if (f.rarity && c.rarity !== f.rarity) return false;
  if (!terms.length) return true;
  const hay = (
    c.name + " " + (c.rulesText || "") + " " + (c.tags || []).join(" ") +
    " " + (c.code || "") + " " + (c.type || "") + " " + c.domains.join(" ")
  ).toLowerCase();
  return terms.every((t) => hay.includes(t));
}

function render() {
  const terms = els.q.value.toLowerCase().split(/\s+/).filter(Boolean);
  const f = {
    set: els.fSet.value, type: els.fType.value,
    domain: els.fDomain.value, rarity: els.fRarity.value,
  };
  filtered = DB.cards.filter((c) => cardMatches(c, terms, f));
  els.empty.hidden = filtered.length > 0;
  els.count.textContent = `(${filtered.length}/${DB.cards.length})`;

  const frag = document.createDocumentFragment();
  for (const c of filtered) {
    const el = document.createElement("div");
    el.className = "card";
    el.tabIndex = 0;
    const land = c.orientation === "landscape" ? " landscape" : "";
    el.innerHTML = `
      <div class="thumb${land}">
        ${c.image
          ? `<img loading="lazy" src="${c.image}" alt="${esc(c.name)}"
               onerror="this.replaceWith(Object.assign(document.createElement('div'),{className:'ph',textContent:'(image offline — tap Download)'}))" />`
          : `<div class="ph">No image</div>`}
      </div>
      <div class="meta">
        <div class="nm">${esc(c.name)}</div>
        <div class="sub">${esc([c.type, c.energy != null ? "⚡" + c.energy : "", c.rarity].filter(Boolean).join(" · "))}</div>
        <div>${c.domains.map((d) => `<span class="pill">${esc(d)}</span>`).join("")}</div>
      </div>`;
    el.addEventListener("click", () => openCard(c));
    el.addEventListener("keydown", (e) => { if (e.key === "Enter") openCard(c); });
    frag.appendChild(el);
  }
  els.grid.replaceChildren(frag);
}

function openCard(c) {
  const land = c.orientation === "landscape" ? " landscape" : "";
  const stat = (label, v) => (v != null && v !== "" ? `<dt>${label}</dt><dd>${esc(String(v))}</dd>` : "");
  els.modal.innerHTML = `
    <button class="close" onclick="document.getElementById('modal').close()">✕ Close</button>
    <div class="modal">
      <div class="art">
        ${c.image
          ? `<img src="${c.image}" alt="${esc(c.name)}"
               onerror="this.replaceWith(Object.assign(document.createElement('div'),{className:'ph',textContent:'Image not downloaded.\\nConnect & tap “Download images”.'}))" />`
          : `<div class="ph">No image</div>`}
      </div>
      <div class="body">
        <h2>${esc(c.name)}</h2>
        <div class="code">${esc(c.code || "")} · ${esc(c.set || "")}</div>
        ${c.rulesText ? `<div class="rules">${esc(c.rulesText)}</div>` : ""}
        <dl class="kv">
          ${stat("Type", c.type)}
          ${stat("Rarity", c.rarity)}
          ${stat("Domains", c.domains.join(", "))}
          ${stat("Energy", c.energy)}
          ${stat("Might", c.might)}
          ${stat("Might Bonus", c.mightBonus)}
          ${stat("Power", c.power)}
          ${stat("Tags", (c.tags || []).join(", "))}
          ${stat("Artist", c.illustrator)}
        </dl>
      </div>
    </div>`;
  els.modal.showModal();
}

const esc = (s) =>
  String(s).replace(/[&<>"']/g, (m) => ({ "&": "&amp;", "<": "&lt;", ">": "&gt;", '"': "&quot;", "'": "&#39;" }[m]));

/* ---- Offline image download ---- */
async function downloadImages() {
  if (!("caches" in window)) { els.imgState.textContent = "Cache API unavailable."; return; }
  const urls = [...new Set(DB.cards.map((c) => c.image).filter(Boolean))];
  const cache = await caches.open(IMG_CACHE);
  els.imgBtn.disabled = true;
  els.imgProg.hidden = false;
  const bar = els.imgProg.firstElementChild;
  let done = 0, failed = 0;
  const queue = urls.slice();
  const worker = async () => {
    while (queue.length) {
      const url = queue.shift();
      try {
        if (!(await cache.match(url))) {
          // The CDN sends no CORS headers, so request opaquely. Opaque responses
          // report status 0 / ok=false but can still be cached and shown in <img>.
          const res = await fetch(url, { mode: "no-cors" });
          if (res.type === "opaque" || res.ok) await cache.put(url, res.clone());
          else failed++;
        }
      } catch { failed++; }
      done++;
      bar.style.width = ((done / urls.length) * 100).toFixed(1) + "%";
      els.imgState.textContent = `${done}/${urls.length}${failed ? ` (${failed} failed)` : ""}`;
    }
  };
  await Promise.all(Array.from({ length: 6 }, worker));
  els.imgBtn.disabled = false;
  els.imgState.textContent = `Cached ${done - failed}/${urls.length} images.`;
  localStorage.setItem("rb-images-cached", String(done - failed));
}

/* ---- Freshness check vs. live gallery ---- */
async function checkFreshness() {
  els.fresh.textContent = "checking for updates…";
  try {
    const res = await fetch("https://riftbound.leagueoflegends.com/en-us/card-gallery/", { mode: "cors" });
    const html = await res.text();
    const live = html.match(/"buildId"\s*:\s*"([^"]+)"/)?.[1];
    if (!live) { els.fresh.textContent = ""; return; }
    if (DB.buildId && live !== DB.buildId) {
      els.fresh.innerHTML = `<span class="dot warn"></span>Update available — re-run the fetch script.`;
    } else {
      els.fresh.innerHTML = `<span class="dot ok"></span>Up to date.`;
    }
  } catch {
    els.fresh.textContent = ""; // offline or CORS-blocked; not an error
  }
}

function setNet() {
  const on = navigator.onLine;
  els.net.innerHTML = `<span class="dot ${on ? "ok" : "off"}"></span>${on ? "Online" : "Offline"}`;
  if (on) checkFreshness();
}

/* ---- Init ---- */
async function init() {
  try {
    DB = await (await fetch("./data/cards.json")).json();
  } catch (e) {
    els.empty.hidden = false;
    els.empty.textContent = "Could not load card data. Run: node scripts/fetch-cards.mjs";
    return;
  }
  fillSelect(els.fSet, DB.sets || []);
  fillSelect(els.fType, DB.types || []);
  fillSelect(els.fDomain, DB.domains || []);
  fillSelect(els.fRarity, DB.rarities || []);
  if (DB.generatedAt) {
    els.gen.textContent = "data: " + new Date(DB.generatedAt).toLocaleDateString();
  }
  const cached = localStorage.getItem("rb-images-cached");
  if (cached) els.imgState.textContent = `${cached} images cached offline.`;

  els.q.addEventListener("input", render);
  for (const s of [els.fSet, els.fType, els.fDomain, els.fRarity]) s.addEventListener("change", render);
  els.imgBtn.addEventListener("click", downloadImages);
  els.modal.addEventListener("click", (e) => { if (e.target === els.modal) els.modal.close(); });
  window.addEventListener("online", setNet);
  window.addEventListener("offline", setNet);

  render();
  setNet();
}
init();
